import { useState, useMemo } from "react";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import { useAppStore } from "../store/appStore";
import V2EmptyState from "../components/V2EmptyState";

function Stat({ label, value, tone = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${tone}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

function severityTone(sev) {
  if (sev === "CRITICAL") return "red";
  if (sev === "WARNING") return "amber";
  return "blue";
}

function actionTone(action) {
  if (action === "HALT") return "red";
  if (action === "RESUME") return "green";
  return "blue";
}

export default function Incidents() {
  const { state } = useAppStore();
  const [severityFilter, setSeverityFilter] = useState("ALL");
  const [sourceFilter, setSourceFilter] = useState("ALL");
  const [search, setSearch] = useState("");

  const { data: telemetry, loading } = usePoll(
    async () => { const r = await http.get("/telemetry/latest"); return r.data; },
    { intervalMs: 15000, enabled: !state.offlineMode }
  );

  /* Extract incidents from telemetry if available */
  const incidents = useMemo(() => {
    if (!telemetry) return [];
    if (Array.isArray(telemetry?.incidents)) return telemetry.incidents;
    return [];
  }, [telemetry]);

  const filtered = useMemo(() => {
    return incidents.filter(inc => {
      if (severityFilter !== "ALL" && inc.severity !== severityFilter) return false;
      if (sourceFilter !== "ALL" && inc.source !== sourceFilter) return false;
      if (search && !inc.message?.toLowerCase().includes(search.toLowerCase()) &&
          !inc.source?.toLowerCase().includes(search.toLowerCase())) return false;
      return true;
    });
  }, [incidents, severityFilter, sourceFilter, search]);

  const openCount = incidents.filter(i => i.status === "OPEN").length;
  const resolvedCount = incidents.filter(i => i.status === "RESOLVED").length;
  const criticalCount = incidents.filter(i => i.severity === "CRITICAL").length;

  const sources = ["ALL", ...new Set(incidents.map(i => i.source).filter(Boolean))];
  const severities = ["ALL", "CRITICAL", "WARNING", "INFO"];

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Incident Log</h1>
            <div className="v2-muted">Loading incident data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  return (
    <>
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Incident Log</h1>
          <div className="v2-muted">Timeline of alerts, failures, overrides, and human actions across all bots.</div>
        </div>
        <div className="v2-row" style={{ gap: 8 }}>
          <input className="v2-input" type="text" placeholder="Search incidents..."
            value={search} onChange={(e) => setSearch(e.target.value)}
            style={{ width: 200, fontSize: 13 }}
          />
        </div>
      </div>

      {/* ── Top Stats ────────────────────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Open Incidents" value={openCount} tone={openCount > 0 ? "red" : "green"} sub="Require attention" />
        <Stat label="Resolved" value={resolvedCount} tone="green" sub="Closed incidents" />
        <Stat label="MTTR" value={"\u2014"} tone="blue" sub="Mean time to resolve" />
        <Stat label="Critical Count" value={criticalCount} tone={criticalCount > 0 ? "red" : "green"} sub="All time today" />
      </div>

      {/* ── Filter Bar ───────────────────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-row" style={{ gap: 12 }}>
            <div className="v2-row" style={{ gap: 8 }}>
              <span className="v2-muted" style={{ fontSize: 13 }}>Severity:</span>
              {severities.map(s => (
                <button key={s} className="v2-btn" onClick={() => setSeverityFilter(s)}
                  style={{
                    padding: "4px 10px", fontSize: 11,
                    background: severityFilter === s ? "rgba(150,190,255,0.12)" : undefined,
                    color: s === "CRITICAL" ? "var(--v2-red)" : s === "WARNING" ? "var(--v2-amber)" : s === "INFO" ? "var(--v2-blue)" : undefined,
                  }}>
                  {s}
                </button>
              ))}
            </div>
            <div className="v2-row" style={{ gap: 8 }}>
              <span className="v2-muted" style={{ fontSize: 13 }}>Source:</span>
              {sources.map(s => (
                <button key={s} className="v2-btn" onClick={() => setSourceFilter(s)}
                  style={{ padding: "4px 10px", fontSize: 11, background: sourceFilter === s ? "rgba(150,190,255,0.12)" : undefined }}>
                  {s}
                </button>
              ))}
            </div>
            <span className="v2-muted" style={{ fontSize: 11, marginLeft: "auto" }}>
              Showing {filtered.length} of {incidents.length}
            </span>
          </div>
        </div>
      </div>

      <div className="v2-grid">
        {/* ── Incident Timeline ───────────────────────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Incident Timeline</div>
          {incidents.length === 0 ? (
            <V2EmptyState icon="\u29C6" title="No Incidents" message="No incidents have been recorded. Incidents will appear here when alerts or failures are detected." />
          ) : (
            <div style={{ maxHeight: 440, overflowY: "auto" }}>
              {filtered.map((inc, idx) => (
                <div key={inc.id || idx} style={{
                  display: "flex", gap: 12, padding: "10px 12px",
                  borderBottom: "1px solid var(--v2-border)",
                  alignItems: "flex-start",
                }}>
                  <div style={{
                    width: 10, height: 10, borderRadius: "50%", flexShrink: 0, marginTop: 4,
                    background: `var(--v2-${severityTone(inc.severity)})`,
                    boxShadow: inc.severity === "CRITICAL" ? "0 0 6px var(--v2-red)" : "none",
                  }} />
                  <div style={{ flex: 1 }}>
                    <div className="v2-row" style={{ justifyContent: "space-between", marginBottom: 4 }}>
                      <div className="v2-row" style={{ gap: 8 }}>
                        <span className={`v2-pill v2-${severityTone(inc.severity)}`}
                          style={{ fontSize: 10, padding: "2px 8px" }}>{inc.severity}</span>
                        <span className="v2-pill" style={{ fontSize: 10, padding: "2px 8px" }}>{inc.source}</span>
                      </div>
                      <div className="v2-row" style={{ gap: 8 }}>
                        <span className={`v2-pill ${inc.status === "OPEN" ? "v2-red" : "v2-green"}`}
                          style={{ fontSize: 10, padding: "2px 8px" }}>{inc.status}</span>
                        <span className="v2-mono v2-muted" style={{ fontSize: 11 }}>{inc.ts}</span>
                      </div>
                    </div>
                    <div style={{ fontSize: 13 }}>{inc.message}</div>
                  </div>
                </div>
              ))}
              {filtered.length === 0 && (
                <div className="v2-muted" style={{ padding: "20px 0", textAlign: "center" }}>
                  No incidents match the current filters.
                </div>
              )}
            </div>
          )}
        </div>

        {/* ── Meta Alerts ─────────────────────────────── */}
        <div className="v2-card half">
          <div className="v2-ct">Meta Alerts</div>
          <div className="v2-muted" style={{ marginBottom: 8 }}>System-wide anomaly summaries</div>
          <V2EmptyState icon="\u29C6" title="No Meta Alerts" message="System-wide anomaly alerts will appear when the telemetry API reports them." />
        </div>

        {/* ── Operator Actions ────────────────────────── */}
        <div className="v2-card half">
          <div className="v2-ct">Operator Actions</div>
          <div className="v2-muted" style={{ marginBottom: 8 }}>HALT / RESUME / APPROVE events</div>
          <V2EmptyState icon="\u29C6" title="No Operator Actions" message="Operator actions (halt, resume, approve) will appear when logged by the control plane." />
        </div>
      </div>
    </>
  );
}
